const ACCEPTED = 'foto clara de ticket o factura (JPG o PNG)';
let raw = $json.content ?? $json.choices?.[0]?.message?.content ?? $json.message?.content ?? $json.text ?? '';
raw = String(raw).trim().replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
let out = { legible: false, ref: '', products: [], detected_type: 'desconocido', reason: 'no_json', accepted_type: ACCEPTED };
try {
  const p = JSON.parse(raw);
  const okShape = p && p.legible === true && typeof p.ref === 'string' && p.ref.trim() !== '' && Array.isArray(p.products) && p.products.length > 0;
  if (okShape) {
    out = { legible: true, ref: p.ref.trim(), products: p.products, detected_type: p.detected_type || 'factura', reason: 'ok', accepted_type: ACCEPTED };
  } else {
    out = { legible: false, ref: (p && p.ref) || '', products: (p && p.products) || [], detected_type: (p && p.detected_type) || 'desconocido', reason: (p && p.reason) || (p && p.legible === false ? 'no_factura' : 'campos_faltantes'), accepted_type: ACCEPTED };
  }
} catch (e) {}
return out;

